-- ============================================================================
-- Mentor-Connect / PeerBridge — LOCAL MOCK/TEST DATABASE SEED (1000 users)
--
-- *** WARNING: This resets the local mock/test database. ***
-- *** It DROPS and recreates all tables below. Do NOT run against production. ***
--
-- Generated deterministically (same content every run) on 2026-07-02.
-- Install:
--   dropdb --if-exists mentor_connect_mock
--   createdb mentor_connect_mock
--   psql mentor_connect_mock -f database/mentor_connect_mock_1000.sql
--
-- Demo logins (all passwords: Password123!):
--   student001@test.edu  (user id 1,   mentee)
--   mentor501@test.edu   (user id 501, mentor)
--   both951@test.edu     (user id 951, both)
-- Fixed sample scenario: Question 1 & Request 1 belong to user 1 (Math/Algebra,
-- 'Mon 5pm'); mentor 501 shares subject+location+language+time+style; mentor 502
-- is an equally strong match but is blocked by user 1 (block-filter demo).
-- ============================================================================

BEGIN;

SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;
SET client_min_messages = warning;

-- ---------------------------------------------------------------------------
-- Drop everything this seed owns (views first, then tables).
-- ---------------------------------------------------------------------------
DROP VIEW IF EXISTS v_popular_subjects, v_mentor_ranks, v_popular_time_slots, v_response_times CASCADE;
DROP TABLE IF EXISTS schedules, questions, request_tags, blocks, reports, requests, users, tags, districts CASCADE;
-- Legacy table names from older student SQL, dropped so re-seeding stays clean.
DROP TABLE IF EXISTS blocked_users CASCADE;

-- ---------------------------------------------------------------------------
-- Schema — product tables (web app) + practice tables (Python/ student code).
-- users includes the additive practice columns (location, available_times,
-- languages, grade_level, teaching_style) expected by Python/get_users.py.
-- ---------------------------------------------------------------------------
CREATE TABLE districts (
    id SERIAL PRIMARY KEY,
    name TEXT NOT NULL,
    county TEXT NOT NULL,
    type TEXT NOT NULL DEFAULT 'unified',
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE tags (
    id SERIAL PRIMARY KEY,
    name TEXT NOT NULL,
    color TEXT NOT NULL DEFAULT '#6366f1',
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE users (
    id SERIAL PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    name TEXT NOT NULL,
    password_hash TEXT NOT NULL,
    role TEXT NOT NULL DEFAULT 'mentee' CHECK (role IN ('mentee', 'mentor', 'both')),
    district_id INTEGER NOT NULL REFERENCES districts(id),
    bio TEXT,
    subjects TEXT[] NOT NULL DEFAULT '{}',
    is_verified BOOLEAN NOT NULL DEFAULT true,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    -- additive practice columns (Python/migrations/001_practice_additive.sql)
    location TEXT,
    available_times TEXT[],
    languages TEXT[],
    grade_level TEXT,
    teaching_style TEXT
);

CREATE TABLE requests (
    id SERIAL PRIMARY KEY,
    author_id INTEGER NOT NULL REFERENCES users(id),
    district_id INTEGER NOT NULL REFERENCES districts(id),
    title TEXT NOT NULL,
    description TEXT NOT NULL,
    role TEXT NOT NULL CHECK (role IN ('mentee', 'mentor')),
    status TEXT NOT NULL DEFAULT 'open' CHECK (status IN ('open', 'matched', 'closed')),
    matched_user_id INTEGER REFERENCES users(id),
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE request_tags (
    id SERIAL PRIMARY KEY,
    request_id INTEGER NOT NULL REFERENCES requests(id) ON DELETE CASCADE,
    tag_id INTEGER NOT NULL REFERENCES tags(id),
    UNIQUE (request_id, tag_id)
);

CREATE TABLE reports (
    id SERIAL PRIMARY KEY,
    reporter_id INTEGER NOT NULL REFERENCES users(id),
    reported_user_id INTEGER NOT NULL REFERENCES users(id),
    reason TEXT NOT NULL,
    description TEXT,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE blocks (
    id SERIAL PRIMARY KEY,
    blocker_id INTEGER NOT NULL REFERENCES users(id),
    blocked_user_id INTEGER NOT NULL REFERENCES users(id),
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE (blocker_id, blocked_user_id)
);

-- Practice table used by Python/get_questions.py and Python/find_matches.py.
CREATE TABLE questions (
    id SERIAL PRIMARY KEY,
    student_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    subject TEXT NOT NULL,
    topic TEXT,
    preferred_time TEXT,
    preferred_language TEXT,
    preferred_teaching_style TEXT,
    message TEXT,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Normalized availability (one row per user per weekly slot). Mirrors
-- users.available_times so students can practice JOIN/GROUP BY scheduling
-- queries; populated below straight from the users table.
CREATE TABLE schedules (
    id SERIAL PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    slot TEXT NOT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE (user_id, slot)
);

CREATE INDEX idx_users_district ON users(district_id);
CREATE INDEX idx_users_role ON users(role);
CREATE INDEX idx_requests_status ON requests(status);
CREATE INDEX idx_requests_district ON requests(district_id);
CREATE INDEX idx_requests_author ON requests(author_id);
CREATE INDEX idx_request_tags_request ON request_tags(request_id);
CREATE INDEX idx_request_tags_tag ON request_tags(tag_id);
CREATE INDEX idx_reports_reported ON reports(reported_user_id);
CREATE INDEX idx_blocks_blocker ON blocks(blocker_id);
CREATE INDEX idx_questions_student ON questions(student_id);
CREATE INDEX idx_schedules_slot ON schedules(slot);

