-- ---------------------------------------------------------------------------
-- schedules — derived 1:1 from users.available_times (always in sync with the
-- data above; ~3000 rows).
-- ---------------------------------------------------------------------------
SELECT u.id, t.slot, u.created_at
FROM users u
CROSS JOIN LATERAL unnest(u.available_times) WITH ORDINALITY AS t(slot, ord)
ORDER BY u.id, t.ord;

-- ---------------------------------------------------------------------------
-- Convenience views for analytics practice (read-only; nothing in the app or
-- the student code writes to these).
-- ---------------------------------------------------------------------------
-- Popular subjects: how many requests carry each tag.
CREATE VIEW v_popular_subjects AS
SELECT t.id AS tag_id, t.name AS subject, COUNT(rt.id)::int AS request_count
FROM tags t
LEFT JOIN request_tags rt ON rt.tag_id = t.id
GROUP BY t.id, t.name
ORDER BY request_count DESC, t.name;

-- Mentor ranks: matched-request counts + average response hours per mentor.
CREATE VIEW v_mentor_ranks AS
SELECT u.id AS mentor_id,
       u.name AS mentor_name,
       COUNT(r.id)::int AS matched_requests,
       ROUND(AVG(EXTRACT(EPOCH FROM (r.updated_at - r.created_at)) / 3600.0)::numeric, 1) AS avg_response_hours
FROM users u
JOIN requests r ON r.matched_user_id = u.id AND r.status = 'matched'
WHERE u.role IN ('mentor', 'both')
GROUP BY u.id, u.name
ORDER BY matched_requests DESC, avg_response_hours ASC;

-- Popular time slots: how many users are available per weekly slot.
CREATE VIEW v_popular_time_slots AS
SELECT slot, COUNT(*)::int AS user_count
FROM schedules
GROUP BY slot
ORDER BY user_count DESC, slot;

-- Response times: hours from request creation to match, for matched requests.
CREATE VIEW v_response_times AS
SELECT r.id AS request_id,
       r.author_id,
       r.matched_user_id,
       ROUND((EXTRACT(EPOCH FROM (r.updated_at - r.created_at)) / 3600.0)::numeric, 1) AS response_hours
FROM requests r
WHERE r.status = 'matched'
ORDER BY r.id;

-- ---------------------------------------------------------------------------
-- Reset sequences past the explicit ids inserted above.
-- ---------------------------------------------------------------------------
SELECT setval('districts_id_seq',    (SELECT MAX(id) FROM districts));
SELECT setval('tags_id_seq',         (SELECT MAX(id) FROM tags));
SELECT setval('users_id_seq',        (SELECT MAX(id) FROM users));
SELECT setval('requests_id_seq',     (SELECT MAX(id) FROM requests));
SELECT setval('request_tags_id_seq', (SELECT MAX(id) FROM request_tags));
SELECT setval('reports_id_seq',      (SELECT MAX(id) FROM reports));
SELECT setval('blocks_id_seq',       (SELECT MAX(id) FROM blocks));
SELECT setval('questions_id_seq',    (SELECT MAX(id) FROM questions));
SELECT setval('schedules_id_seq',    (SELECT MAX(id) FROM schedules));

COMMIT;

